import React from "react";
import styles from "./option.module.css";

interface OptionProps {
  title: string;
  desc?: string;
  isDropdown?: boolean;
}

const Option: React.FC<OptionProps> = ({ title, desc, isDropdown }) => {
  return (
    <label className={styles.wrapper_option}>
      <input type="radio" name="options" id={title} />
      <div className={styles.option_content}>
        <div className={styles.option_content_top}>

        </div>
        <span className={styles.option_title}>{title}</span>
        {isDropdown && (
          <div className={styles.option_dropdown}>
            <select>
              <option value="4weeks">4 weeks</option>
              <option value="2weeks">2 weeks</option>
              <option value="1week">1 week</option>
            </select>
          </div>
        )}
        {desc && <p className={styles.option_desc}>{desc}</p>}

      </div>
    </label>
  );
};

export default Option;
